  1→/**
  2→ * Behavior HTTP Route Handlers
  3→ *
  4→ * Thin composition layer: parses HTTP requests, delegates to query functions,
  5→ * returns JSON responses. No domain logic lives here.
  6→ */
  7→import { logError } from "../http/observability";
  8→import { jsonError, jsonResponse } from "../http/response";
  9→import type { ServerDependencies } from "../runtime/types";
 10→import {
 11→  listWorkspaceBehaviors,
 12→  listBehaviors,
 13→  createBehaviorDefinition,
 14→  getBehaviorDefinition,
 15→  listBehaviorDefinitions,
 16→  updateBehaviorDefinition,
 17→  type BehaviorRow,
 18→} from "./queries";
 19→import type {
 20→  BehaviorDefinitionRecord,
 21→  CreateBehaviorDefinitionInput,
 22→  UpdateBehaviorDefinitionInput,
 23→} from "./definition-types";
 24→import { matchDefinitions } from "./definition-matcher";
 25→import { dispatchScoring, type ScoredResult } from "./scorer-dispatcher";
 26→
 27→// ---------------------------------------------------------------------------
 28→// Response serialization (pure)
 29→// ---------------------------------------------------------------------------
 30→
 31→function serializeBehavior(record: BehaviorRow) {
 32→  return {
 33→    id: record.id.id as string,
 34→    metric_type: record.metric_type,
 35→    score: record.score,
 36→    source_telemetry: record.source_telemetry,
 37→    definition_id: record.definition.id as string,
 38→    definition_version: record.definition_version,
 39→    workspace_id: record.workspace.id as string,
 40→    ...(record.session ? { session_id: record.session.id as string } : {}),
 41→    created_at: record.created_at,
 42→  };
 43→}
 44→
 45→function serializeDefinition(record: BehaviorDefinitionRecord) {
 46→  return {
 47→    id: record.id.id as string,
 48→    title: record.title,
 49→    goal: record.goal,
 50→    scoring_logic: record.scoring_logic,
 51→    telemetry_types: record.telemetry_types,
 52→    ...(record.category !== undefined ? { category: record.category } : {}),
 53→    status: record.status,
 54→    version: record.version,
 55→    enforcement_mode: record.enforcement_mode,
 56→    ...(record.enforcement_threshold !== undefined ? { enforcement_threshold: record.enforcement_threshold } : {}),
 57→    workspace_id: record.workspace.id as string,
 58→    ...(record.created_by ? { created_by_id: record.created_by.id as string } : {}),
 59→    created_at: record.created_at,
 60→    ...(record.updated_at ? { updated_at: record.updated_at } : {}),
 61→  };
 62→}
 63→
 64→// ---------------------------------------------------------------------------
 65→// Route handler factory
 66→// ---------------------------------------------------------------------------
 67→
 68→export function createBehaviorRouteHandlers(deps: ServerDependencies) {
 69→  return {
 70→    handleList: (workspaceId: string, request: Request) =>
 71→      handleListBehaviors(deps, workspaceId, request),
 72→    handleScore: (workspaceId: string, request: Request) =>
 73→      handleScoreTelemetry(deps, workspaceId, request),
 74→    handleCreateDefinition: (workspaceId: string, request: Request) =>
 75→      handleCreateDefinition(deps, workspaceId, request),
 76→    handleListDefinitions: (workspaceId: string, request: Request) =>
 77→      handleListDefinitions(deps, workspaceId, request),
 78→    handleGetDefinition: (workspaceId: string, definitionId: string) =>
 79→      handleGetDefinition(deps, workspaceId, definitionId),
 80→    handleUpdateDefinition: (workspaceId: string, definitionId: string, request: Request) =>
 81→      handleUpdateDefinition(deps, workspaceId, definitionId, request),
 82→  };
 83→}
 84→
 85→// ---------------------------------------------------------------------------
 86→// GET /api/workspaces/:workspaceId/behaviors
 87→// ---------------------------------------------------------------------------
 88→
 89→async function handleListBehaviors(
 90→  deps: ServerDependencies,
 91→  workspaceId: string,
 92→  request: Request,
 93→): Promise<Response> {
 94→  try {
 95→    const url = new URL(request.url);
 96→    const metricType = url.searchParams.get("metric_type") ?? undefined;
 97→    const identityId = url.searchParams.get("identity_id") ?? undefined;
 98→
 99→    let records: BehaviorRow[];
100→
101→    if (identityId) {
102→      // Query by identity traversing exhibits edges
103→      records = await listBehaviors(deps.surreal, identityId, metricType);
104→      // Filter to workspace scope
105→      records = records.filter((r) => (r.workspace.id as string) === workspaceId);
106→    } else {
107→      // Query by workspace directly
108→      records = await listWorkspaceBehaviors(deps.surreal, workspaceId, metricType);
109→    }
110→
111→    return jsonResponse({
112→      behaviors: records.map(serializeBehavior),
113→    }, 200);
114→  } catch (error) {
115→    logError("behavior.list.failed", "Failed to list behaviors", error, { workspaceId });
116→    return jsonError("failed to list behaviors", 500);
117→  }
118→}
119→
120→// ---------------------------------------------------------------------------
121→// POST /api/workspaces/:workspaceId/behaviors/score
122→// ---------------------------------------------------------------------------
123→
124→function serializeScoredResult(result: ScoredResult) {
125→  return {
126→    behaviorId: result.behaviorId,
127→    metricType: result.definitionTitle,
128→    score: result.score,
129→    definitionId: result.definitionId,
130→    definitionVersion: result.definitionVersion,
131→    ...(result.rationale ? { rationale: result.rationale } : {}),
132→    ...(result.evidenceChecked ? { evidenceChecked: result.evidenceChecked } : {}),
133→  };
134→}
135→
136→async function handleScoreTelemetry(
137→  deps: ServerDependencies,
138→  workspaceId: string,
139→  request: Request,
140→): Promise<Response> {
141→  try {
142→    let body: Record<string, unknown>;
143→    try {
144→      body = (await request.json()) as Record<string, unknown>;
145→    } catch {
146→      return jsonError("Request body must be valid JSON", 400);
147→    }
148→
149→    const telemetryType = body.telemetry_type as string | undefined;
150→    const identityId = body.identity_id as string | undefined;
151→    const payload = body.payload as Record<string, unknown> | undefined;
152→
153→    if (!telemetryType || telemetryType.trim().length === 0) return jsonError("telemetry_type is required", 400);
154→    if (!identityId || identityId.trim().length === 0) return jsonError("identity_id is required", 400);
155→    if (!payload || typeof payload !== "object") return jsonError("payload must be an object", 400);
156→
157→    // Query all definitions for this workspace, then filter by active + telemetry type
158→    const allDefinitions = await listBehaviorDefinitions(deps.surreal, workspaceId);
159→    const matched = matchDefinitions(allDefinitions, telemetryType);
160→
161→    if (matched.length === 0) {
162→      return jsonResponse({ results: [], matched_definitions: 0 }, 200);
163→    }
164→
165→    // Dispatch scoring for all matched definitions
166→    const scored = await dispatchScoring(
167→      matched,
168→      {
169→        telemetryType,
170→        telemetryPayload: payload,
171→        identityId,
172→        workspaceId,
173→      },
174→      {
175→        surreal: deps.surreal,
176→        scorerModel: deps.scorerModel,
177→      },
178→    );
179→
180→    return jsonResponse({
181→      results: scored.map(serializeScoredResult),
182→      matched_definitions: matched.length,
183→    }, 200);
184→  } catch (error) {
185→    logError("behavior.score.failed", "Failed to score telemetry", error, { workspaceId });
186→    return jsonError("failed to score telemetry", 500);
187→  }
188→}
189→
190→// ---------------------------------------------------------------------------
191→// POST /api/workspaces/:workspaceId/behavior-definitions
192→// ---------------------------------------------------------------------------
193→
194→async function handleCreateDefinition(
195→  deps: ServerDependencies,
196→  workspaceId: string,
197→  request: Request,
198→): Promise<Response> {
199→  try {
200→    let body: Record<string, unknown>;
201→    try {
202→      body = (await request.json()) as Record<string, unknown>;
203→    } catch {
204→      return jsonError("Request body must be valid JSON", 400);
205→    }
206→
207→    const title = body.title as string | undefined;
208→    const goal = body.goal as string | undefined;
209→    const scoringLogic = body.scoring_logic as string | undefined;
210→    const telemetryTypes = body.telemetry_types as string[] | undefined;
211→    const category = body.category as string | undefined;
212→    const createdById = body.created_by_id as string | undefined;
213→
214→    if (!title || title.trim().length === 0) return jsonError("title is required", 400);
215→    if (!goal || goal.trim().length === 0) return jsonError("goal is required", 400);
216→    if (!scoringLogic || scoringLogic.trim().length === 0) return jsonError("scoring_logic is required", 400);
217→    if (!telemetryTypes || !Array.isArray(telemetryTypes) || telemetryTypes.length === 0) return jsonError("telemetry_types must be a non-empty array", 400);
218→    if (!createdById || createdById.trim().length === 0) return jsonError("created_by_id is required", 400);
219→
220→    const input: CreateBehaviorDefinitionInput = {
221→      title: title.trim(),
222→      goal: goal.trim(),
223→      scoring_logic: scoringLogic.trim(),
224→      telemetry_types: telemetryTypes,
225→      ...(category !== undefined ? { category } : {}),
226→    };
227→
228→    const { definitionId } = await createBehaviorDefinition(
229→      deps.surreal,
230→      workspaceId,
231→      createdById,
232→      input,
233→    );
234→
235→    const record = await getBehaviorDefinition(deps.surreal, definitionId);
236→    if (!record) return jsonError("failed to retrieve created definition", 500);
237→
238→    return jsonResponse({ definition: serializeDefinition(record) }, 201);
239→  } catch (error) {
240→    logError("behavior.definition.create.failed", "Failed to create behavior definition", error, { workspaceId });
241→    return jsonError("failed to create behavior definition", 500);
242→  }
243→}
